mapper.select:
SELECT org.id , org.pid, org.name, org.height, org.tenant_id as tenantId,org.create_time as createTime ,org.update_time as updateTime, org.description, org.org_order as orgOrder ,moe.custom_id, moh.director, moh.phone, org.org_pinyin AS orgPinyin, org.org_pinyins AS orgPinyin2 FROM md_org org LEFT JOIN md_org_external moe on org.id = moe.org_id LEFT JOIN md_org_head moh on org.id = moh.org_id WHERE org.tenant_id = #{tenantId}
AND org.id IN
#{orgId}
ORDER BY org.org_order , org.create_time

SELECT org.id , org.pid, org.name, org.height, org.tenant_id as tenantId,org.create_time as createTime ,org.update_time as updateTime, org.description, org.org_order as orgOrder ,moe.custom_id, moh.director, moh.phone, org.org_pinyin AS orgPinyin, org.org_pinyins AS orgPinyin2 FROM md_org org LEFT JOIN md_org_external moe on org.id = moe.org_id LEFT JOIN md_org_head moh on org.id = moh.org_id WHERE org.tenant_id = #{tenantId} and org.pid=#{companyId}
AND org.id IN
#{orgId}
ORDER BY org.org_order , org.create_time

SELECT org.*, moe.custom_id AS customId
FROM md_org org
LEFT JOIN md_org_external moe on org.id = moe.org_id
WHERE org.tenant_id = #{tenantId}
AND org.id = #{id}

SELECT org.*, moe.custom_id AS customId
FROM md_org org
LEFT JOIN md_org_external moe on org.id = moe.org_id
WHERE org.tenant_id = #{tenantId}
AND org.pid = #{pid}
AND org.name = #{name}
limit 1

SELECT org.*, moe.custom_id AS customId
FROM md_org org
LEFT JOIN md_org_external moe on org.id = moe.org_id
WHERE org.tenant_id = #{tenantId}
AND org.name = #{name}

SELECT org.id , org.pid, org.name, org.height, org.tenant_id as tenantId, moe.custom_id, org.org_pinyin AS orgPinyin, org.org_pinyins AS orgPinyin2 FROM md_org org LEFT JOIN md_org_external moe on org.id = moe.org_id WHERE org.tenant_id = #{tenantId}
and org.id in
#{orgId}
ORDER BY org.org_order ASC ,org.create_time
